import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.C6K0jwmI.js";const _=JSON.parse('{"title":"予約管理","description":"","frontmatter":{"title":"予約管理"},"headers":[],"relativePath":"tenant/24-reservations.md","filePath":"tenant/24-reservations.md"}'),i={name:"tenant/24-reservations.md"};function o(l,t,h,n,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="_24-予約管理" tabindex="-1">24. 予約管理 <a class="header-anchor" href="#_24-予約管理" aria-label="Permalink to &quot;24. 予約管理&quot;">​</a></h1><p>予約管理では、予約受付、予約台帳、空席確認、来店処理、キャンセル、予約金、コース予約を管理します。</p><h2 id="予約受付の流れ" tabindex="-1">予約受付の流れ <a class="header-anchor" href="#予約受付の流れ" aria-label="Permalink to &quot;予約受付の流れ&quot;">​</a></h2><ol><li>お客様が予約ページを開きます。</li><li>日時、人数、連絡先、希望内容を入力します。</li><li>店舗側の予約台帳に反映されます。</li><li>来店時に予約を確認し、席へ案内します。</li><li>必要に応じてテーブル開放や注文へ進みます。</li></ol><h2 id="予約台帳" tabindex="-1">予約台帳 <a class="header-anchor" href="#予約台帳" aria-label="Permalink to &quot;予約台帳&quot;">​</a></h2><p>予約台帳では、日付、時間、人数、氏名、連絡先、コース、ステータスを確認します。営業前に当日の予約を確認し、席と人員を準備してください。</p><h2 id="予約ステータス" tabindex="-1">予約ステータス <a class="header-anchor" href="#予約ステータス" aria-label="Permalink to &quot;予約ステータス&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ステータス</th><th>意味</th></tr></thead><tbody><tr><td>受付済み</td><td>予約が登録された状態</td></tr><tr><td>来店済み</td><td>お客様が来店し、案内済みの状態</td></tr><tr><td>キャンセル</td><td>予約が取り消された状態</td></tr><tr><td>無断キャンセル</td><td>予約時間を過ぎても来店がない状態</td></tr></tbody></table><h2 id="予約金" tabindex="-1">予約金 <a class="header-anchor" href="#予約金" aria-label="Permalink to &quot;予約金&quot;">​</a></h2><p>予約金を利用する場合は、対象コース、返金条件、キャンセルポリシーを事前に明確にしてください。お客様への案内文も確認してください。</p><h2 id="ai予約" tabindex="-1">AI予約 <a class="header-anchor" href="#ai予約" aria-label="Permalink to &quot;AI予約&quot;">​</a></h2><p>AI予約は自然文から予約内容を読み取る補助機能です。最終的な日時、人数、コース、連絡先は必ず店舗側で確認してください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>予約が表示されない</td><td>日付、店舗、ステータスを確認してください。</td></tr><tr><td>席が足りない</td><td>フロアマップ、予約人数、滞在時間を確認してください。</td></tr><tr><td>キャンセル処理したい</td><td>店舗のキャンセルポリシーに従って処理してください。</td></tr><tr><td>予約金の扱いが分からない</td><td>決済履歴と店舗ルールを確認し、必要に応じてPOSLAサポートへお問い合わせください。</td></tr></tbody></table>',14)])])}const p=a(i,[["render",o]]);export{_ as __pageData,p as default};
